#include <stdlib.h>
#include <stdbool.h>
#include <string.h>

typedef struct prefixTree {
    struct prefixTree* children[26];
    bool nullValue;
} prefixTree;

prefixTree* createPrefixTree() {
    prefixTree* currentObject = (prefixTree*)malloc(sizeof(prefixTree));
    memset(currentObject->children, 0, sizeof(currentObject->children));
    currentObject->nullValue = false;
    return currentObject;
}

void addWord(prefixTree* currentObject, char* textString) {
    prefixTree* node = currentObject;
    for (int i = 0; textString[i]; i++) {
        int idx = textString[i] - 'a';
        if (!node->children[idx]) node->children[idx] = createPrefixTree();
        node = node->children[idx];
    }
    node->nullValue = true;
}

bool findWord(prefixTree* currentObject, char* textString) {
    prefixTree* node = currentObject;
    for (int i = 0; textString[i]; i++) {
        int idx = textString[i] - 'a';
        if (!node->children[idx]) return false;
        node = node->children[idx];
    }
    return node->nullValue;
}

bool startsWithPrefixCheck(prefixTree* currentObject, char* wordPrefix) {
    prefixTree* node = currentObject;
    for (int i = 0; wordPrefix[i]; i++) {
        int idx = wordPrefix[i] - 'a';
        if (!node->children[idx]) return false;
        node = node->children[idx];
    }
