class Codechef {
    private static 
    private final TrieNode root;
    public Codechef() {
        root = new TrieNode();
    }
    public void insert(String addWord) {
        TrieNode node = root;
        for (int i = 0; i < addWord.length(); i++) {
            int idx = addWord.charAt(i) - 'a';
            if (node.children[idx] == null) node.children[idx] = new TrieNode();
            node = node.children[idx];
        }
        node.isWord = true;
    }
    public boolean search(String findWord) {
        TrieNode node = root;
        for (int i = 0; i < findWord.length(); i++) {
            int idx = findWord.charAt(i) - 'a';
            if (node.children[idx] == null) return false;
            node = node.children[idx];
        }
        return node.isWord;
    }
    public boolean startsWith(String startsWithPrefix) {
        TrieNode node = root;
        for (int i = 0; i < startsWithPrefix.length(); i++) {
            int idx = startsWithPrefix.charAt(i) - 'a';
            if (node.children[idx] == null) return false;
            node = node.children[idx];
        }
        return true;
    }
}
